import{_ as e,o,c as t,a}from"./app.23d84491.js";const w=JSON.parse('{"title":"TheOrangeWizard v. ArowShot, Jan 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]}],"relativePath":"government/court-cases-precedents/theorangewizard_v_arowshot_jan_2018.md","lastUpdated":1666055355000}'),n={name:"government/court-cases-precedents/theorangewizard_v_arowshot_jan_2018.md"},i=a('<h1 id="theorangewizard-v-arowshot-jan-2018" tabindex="-1">TheOrangeWizard v. ArowShot, Jan 2018 <a class="header-anchor" href="#theorangewizard-v-arowshot-jan-2018" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: Mightyoddish</p><p><strong>Date</strong>: 29th January 2018</p><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>Dereliction of ArowShot&#39;s house.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><blockquote><p>My house is the last mark I&#39;ve left on Yoahtl in CivClassic, in a town I helped found, in the forest I helped clear on the first day with Leib, and after being with Yoahtl for several years and serving Yoahtl as a councillor for 4 months, I don&#39;t want my last mark to be erased. I understand the need for space which is why I would be okay with renting the house out (without cost) to trusted newfriends or oldfriends, and I understand that it while it is unfinished it may not look the best so I am also willing to finish it in a timely manner.</p></blockquote><p>-ArowShot</p></li><li><blockquote><p>Arow, you have contributed a lot to Yoahtl during your time here and we all greatly appreciate it. However, NYC is a living city that changes with its population. Many houses that have been built in the past and have since been replaced as their owners move away and new people join the community. The exception is your house, which has been granted a de facto exemption from dereliction. The prosecution sees no reason why this should continue, when the houses of Leib and many other old Yoahtlans have been given no such special treatment.</p></blockquote><p>-TheOrangeWizard</p></li><li><p>Some back and forth in which Orange disputes the fact that because you contributed historically you&#39;re immune from dereliction</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><blockquote><p>So, how I see this is the usual time we wait for dereliction to be considered is 2 months, you have had much longer to find someone to fit into your house, but only now when your house is in danger you choose to announce this and speak up. The space is needed greatly and people have long called for it to go or for a plot to live in. I do see your point about being a long time contributor however you&#39;ve been long enough inactive and have taken no action to save it before now, besides the resident you may strike a deal with may want to change the house.. it&#39;s best to start over. @ArowShot the forever oof im afraid these isnt a good enough jsutification to see why to keep your inactive house...</p></blockquote><p>-MightyOddish</p>',10),r=[i];function s(h,d,c,l,u,p){return o(),t("div",null,r)}const m=e(n,[["render",s]]);export{w as __pageData,m as default};
